// // This is a 3-bit shift register with enable. At each clock cycle:
// - If enable = 1, shift the bits to the left, and shift in the value of 'in' at the rightmost position.
// - If enable = 0, hold the current value.
module top_module(
	input clk,
	input enable,
	input in,
	output [2:0] q);logic [2:0] q_reg;

	always @(posedge clk)
		if (enable) q_reg <= {in, q_reg[2:1]};

	assign q = q_reg;

endmodule

